INSERT INTO apt_appointment_status_history (
    history_id, tenant_id, appointment_id, aggregate_version, from_status, to_status,
    command_code, actor_id, reason_code, revision_id, occurred_at
) VALUES (
    #{historyId}, #{tenantId}, #{appointmentId}, #{aggregateVersion}, #{fromStatus}, #{toStatus},
    #{commandCode}, #{actorId}, #{reasonCode}, #{revisionId}, #{occurredAt}
)

INSERT INTO apt_appointment_command_result (
    tenant_id, operation_type, idempotency_key, appointment_id, revision_id,
    status, revision_no, aggregate_version, occurred_at
) VALUES (
    #{tenantId}, #{operationType}, #{idempotencyKey}, #{appointmentId}, #{revisionId},
    #{status}, #{revisionNo}, #{aggregateVersion}, #{occurredAt}
)

mapper.select:
SELECT appointment_id AS "appointmentId", revision_id AS "revisionId", status,
       revision_no AS "revisionNo", aggregate_version AS "aggregateVersion",
       occurred_at AS "occurredAt"
  FROM apt_appointment_command_result
 WHERE tenant_id = #{tenantId} AND operation_type = #{operationType}
   AND idempotency_key = #{idempotencyKey}
